# Unit Tests for `zip_dicts`

```python
import pytest


def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}


class TestZipDicts:
    """Test suite for zip_dicts function."""

    # Happy path tests
    def test_zip_two_dicts_with_same_keys(self):
        """Test zipping two dictionaries with identical keys."""
        d1 = {"a": 1, "b": 2}
        d2 = {"a": 3, "b": 4}
        result = zip_dicts(d1, d2)
        assert result == {"a": [1, 3], "b": [2, 4]}

    def test_zip_three_dicts_with_same_keys(self):
        """Test zipping three dictionaries with identical keys."""
        d1 = {"x": 10, "y": 20}
        d2 = {"x": 30, "y": 40}
        d3 = {"x": 50, "y": 60}
        result = zip_dicts(d1, d2, d3)
        assert result == {"x": [10, 30, 50], "y": [20, 40, 60]}

    def test_zip_dicts_with_different_keys(self):
        """Test zipping dictionaries with different keys."""
        d1 = {"a": 1, "b": 2}
        d2 = {"b": 3, "c": 4}
        result = zip_dicts(d1, d2)
        assert result == {"a": [1, None], "b": [2, 3], "c": [None, 4]}

    def test_zip_dicts_with_completely_different_keys(self):
        """Test zipping dictionaries with no overlapping keys."""
        d1 = {"a": 1}
        d2 = {"b": 2}
        d3 = {"c": 3}
        result = zip_dicts(d1, d2, d3)
        assert result == {"a": [1, None, None], "b": [None, 2, None], "c": [None, None, 3]}

    def test_zip_dicts_with_various_value_types(self):
        """Test zipping dictionaries with different value types."""
        d1 = {"a": 1, "b": "string", "c": 3.14}
        d2 = {"a": [1, 2], "b": {"nested": "dict"}, "c": True}
        result = zip_dicts(d1, d2)
        assert result == {
            "a": [1, [1, 2]],
            "b": ["string", {"nested": "dict"}],
            "c": [3.14, True],
        }

    # Edge cases
    def test_zip_single_dict(self):
        """Test zipping a single dictionary."""
        d1 = {"a": 1, "b": 2}
        result = zip_dicts(d1)
        assert result == {"a": [1], "b": [2]}

    def test_zip_empty_dicts(self):
        """Test zipping empty dictionaries."""
        d1 = {}
        d2 = {}
        result = zip_dicts(d1, d2)
        assert result == {}

    def test_zip_one_empty_one_non_empty(self):
        """Test zipping one empty and one non-empty dictionary."""
        d1 = {}
        d2 = {"a": 1, "b": 2}
        result = zip_dicts(d1, d2)
        assert result == {"a": [None, 1], "b": [None, 2]}

    def test_zip_no_dicts(self):
        """Test zipping with no dictionaries."""
        result = zip_dicts()
        assert result == {}

